) AS (VALUES
  -- Фаза 1 → Фаза 2 (купирование боли → восстановление движений)
  (1, 'pain_rest_tolerable',    'Боль в покое держится на приемлемом уровне (≤ 3 из 10)',                      'measurement',      'vas_score'::varchar, 'pain'::varchar, '<='::varchar, 3::numeric, NULL::numeric, 7::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'passive_flexion_120',    'Пассивное сгибание (подъём руки вперёд при поддержке) ≥ 120°',                'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'daily_below_shoulder',   'Бытовые движения ниже уровня плеча без резкой боли',                         'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете выполнять бытовые движения ниже уровня плеча без резкой боли?', 'Например: одеться, поесть, взять предмет с полки на уровне пояса', 30::smallint, TRUE),
  (1, 'pain_settles_morning',   'Боль после упражнений стихает к утру и не усиливается ночью',                'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Стихает боль после упражнений к утру, не усиливаясь ночью?', 'Сравните боль вечером после занятия и на следующее утро', 40::smallint, TRUE),
  (1, 'painfree_isometrics',    'Базовые безболезненные движения и изометрии манжеты без выраженной боли',    'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),
  -- Фаза 2 → Фаза 3 (восстановление движений → прогрессивное укрепление)
  (2, 'active_flexion_140',     'Активное сгибание (самостоятельный подъём руки вперёд) ≥ 140°',               'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'active_abduction_120',   'Активное отведение (подъём руки в сторону) ≥ 120° без выраженной компенсации','instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'pain_active_tolerable',  'Боль при активных движениях держится приемлемой (≤ 3 из 10)',                'measurement',      'vas_score', 'pain', '<=', 3::numeric, NULL, 7::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'arm_to_shoulder_level',  'Удаётся поднять руку до уровня плеча и выше без резкой боли',                'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете поднять руку до уровня плеча и выше без резкой боли?', 'Оцените подъём руки вперёд и в сторону', 40::smallint, TRUE),
  (2, 'scapular_control_ok',    'Нет выраженной болезненной дуги при подъёме руки, лопатка работает правильно','instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),
  -- Фаза 3 → Фаза 4 (укрепление → возврат к функции/спорту)
  (3, 'er_strength_80pct',      'Сила наружного поворота ≥ 80% от здоровой руки (динамометрия)',              'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'active_rom_90pct',       'Активный объём движений ≥ 90% от здоровой стороны (или полный безболезненный)','instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'pain_strength_tolerable','Боль при силовых упражнениях ≤ 3 из 10 и стихает к утру',                    'measurement',      'vas_score', 'pain', '<=', 3::numeric, NULL, 7::smallint, NULL, NULL, 30::smallint, TRUE),
  (3, 'loaded_tasks_painfree',  'Нагрузочные бытовые задачи без усиления боли',                              'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете выполнять нагрузочные бытовые задачи без усиления боли?', 'Например: нести сумку, толкнуть дверь, поработать рукой над головой', 40::smallint, TRUE),
  (3, 'dynamic_stability_ok',   'Устойчивость и контроль плеча при динамических упражнениях, без компенсаций', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),
  -- Фаза 4 (возврат к функции/спорту — критерии готовности, последний переход)
  (4, 'rotator_strength_90pct', 'Сила мышц-ротаторов ≥ 90% от здоровой руки (для рабочей руки/спортсменов — до 100–110%)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (4, 'full_painfree_rom',      'Полный безболезненный объём движений, сопоставимый со здоровой стороной',     'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (4, 'ready_and_confident',    'Есть готовность и доверие к плечу при полной нагрузке',                      'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Чувствуете готовность вернуться к спорту/работе и доверяете плечу при полной нагрузке?', 'Оцените уверенность при привычных нагрузочных движениях', 30::smallint, TRUE),
  (4, 'sport_tests_passed',     'Спорт- и работо-специфичные тесты выполняются без боли и компенсаций',       'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 40::smallint, FALSE),
  (4, 'clinical_judgement_ok',  'По части функциональных тестов универсального порога нет — оценивает куратор очно', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_rc_conservative' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
